/*
 * Embedded Sensor Node - IoT Device Implementation
 * Simulates a temperature sensor node with sleep mode and data transmission
 * Suitable for ESP32 or similar microcontrollers
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <time.h>

// Configuration constants
#define NODE_ID 1
#define TEMP_SENSOR_PIN 4
#define BATTERY_ADC_PIN 5
#define RX_BUFFER_SIZE 64
#define TX_BUFFER_SIZE 128
#define SLEEP_INTERVAL_MS 5000
#define TEMP_THRESHOLD 25.0

// Sensor reading structure
typedef struct {
 int node_id;
 float temperature;
 float battery_level;
 unsigned long timestamp;
 bool alert_flag;
} SensorData;

// Global variables
static SensorData sensor_reading;
static bool device_active = true;

/* Function prototypes */
void init_hardware(void);
float read_temperature_sensor(int pin);
float read_battery_level(int adc_pin);
unsigned long get_timestamp(void);
bool should_transmit(float temperature);
void transmit_data(SensorData *data);
void enter_deep_sleep(int duration_ms);
void process_command(char *command);

/* Initialize hardware peripherals */
void init_hardware(void) {
 printf("[HW] Initializing sensor node hardware...\n");
 printf("[HW] Temperature sensor on GPIO%d\n", TEMP_SENSOR_PIN);
 printf("[HW] Battery ADC on GPIO%d\n", BATTERY_ADC_PIN);
 printf("[HW] WiFi/BLE transceiver initialized\n");
 printf("[HW] Hardware initialization complete\n\n");
}

/* Simulate temperature sensor reading */
float read_temperature_sensor(int pin) {
 // In real hardware, this would read from ADC/I2C
 // Simulating with pseudo-random value around 24-28°C
 float base_temp = 24.0;
 float variation = (rand() % 50) / 10.0; // 0.0 to 5.0
 return base_temp + variation;
}

/* Read battery voltage level */
float read_battery_level(int adc_pin) {
 // Simulate battery between 3.0V and 4.2V
 return 3.0 + (rand() % 120) / 100.0;
}

/* Get current timestamp in milliseconds */
unsigned long get_timestamp(void) {
 return (unsigned long)time(NULL) * 1000;
}

/* Determine if data should be transmitted */
bool should_transmit(float temperature) {
 // Transmit if temperature exceeds threshold or on regular intervals
 return (temperature > TEMP_THRESHOLD);
}

/* Transmit sensor data via IoT protocol (BLE/WiFi/LoRa) */
void transmit_data(SensorData *data) {
 char tx_buffer[TX_BUFFER_SIZE];

 // Format data as JSON for cloud transmission
 snprintf(tx_buffer, TX_BUFFER_SIZE,
 "{\"node_id\":%d, \"temp\":%.2f, \"battery\":%.2f, \"ts\":%lu, \"alert\":%s}",
 data->node_id,
 data->temperature,
 data->battery_level,
 data->timestamp,
 data->alert_flag ? "true" : "false"
 );

 printf("[TX] Transmitting data: %s\n", tx_buffer);
 printf("[TX] Protocol: MQTT over BLE/WiFi\n");
 printf("[TX] Transmission complete!\n\n");
}

/* Enter low-power deep sleep mode */
void enter_deep_sleep(int duration_ms) {
 printf("[PWR] Entering deep sleep mode for %d ms\n", duration_ms);
 printf("[PWR] CPU halted, sensors in standby\n");
 // In real hardware: esp_deep_sleep_start();
}

/* Process incoming cloud commands */
void process_command(char *command) {
 printf("[RX] Received command: %s\n", command);

 if (strstr(command, "SET_THRESHOLD")) {
 printf("[CMD] Updating temperature threshold\n");
 } else if (strstr(command, "FIRMWARE_UPDATE")) {
 printf("[CMD] Initiating OTA firmware update\n");
 } else if (strstr(command, "RESET")) {
 printf("[CMD] Resetting node...\n");
 device_active = false;
 }
}

/* Main sensor node program */
int main(void) {
 printf("\n========================================\n");
 printf(" IoT SENSOR NODE v1.0 - Node #%d\n", NODE_ID);
 printf("========================================\n\n");

 // Initialize hardware
 init_hardware();

 // Main loop
 int loop_count = 0;
 while (device_active && loop_count < 3) {
 printf("--- Sampling Cycle #%d ---\n", loop_count + 1);

 // Step 1: Read temperature sensor
 sensor_reading.temperature = read_temperature_sensor(TEMP_SENSOR_PIN);
 printf("[SENSOR] Temperature: %.2f°C\n", sensor_reading.temperature);

 // Step 2: Read battery level
 sensor_reading.battery_level = read_battery_level(BATTERY_ADC_PIN);
 printf("[SENSOR] Battery: %.2fV\n", sensor_reading.battery_level);

 // Step 3: Store metadata
 sensor_reading.node_id = NODE_ID;
 sensor_reading.timestamp = get_timestamp();
 sensor_reading.alert_flag = should_transmit(sensor_reading.temperature);

 // Step 4: Decide transmission
 if (should_transmit(sensor_reading.temperature)) {
 printf("[STATUS] Threshold exceeded - transmitting\n");
 transmit_data(&sensor_reading);
 } else {
 printf("[STATUS] Normal readings - no transmission\n");
 }

 // Step 5: Simulate receiving commands
 if (loop_count == 1) {
 process_command("SET_THRESHOLD:30");
 }

 // Step 6: Enter sleep mode to conserve power
 enter_deep_sleep(SLEEP_INTERVAL_MS);

 loop_count++;
 printf("\n");
 }

 printf("[SYSTEM] Sensor node shutting down\n");
 return 0;
}

/*
 * Compilation: gcc -o sensor_node sensor_node.c
 * Output demonstrates embedded IoT device lifecycle:
 * 1. Hardware initialization
 * 2. Sensor reading (temperature, battery)
 * 3. Data transmission decision
 * 4. Low-power sleep mode
 * 5. Command processing
 */
